+		enabledCollector: map[dcgm.Field_Entity_Group]struct{}{
+			dcgm.FE_SWITCH: struct{}{},
+		},
+	}, {
+		name: "gpu_link",
+		enabledCollector: map[dcgm.Field_Entity_Group]struct{}{
+			dcgm.FE_LINK: struct{}{},
+		},
+	}, {
+		name: "gpu_cpu",
+		enabledCollector: map[dcgm.Field_Entity_Group]struct{}{
+			dcgm.FE_CPU: struct{}{},
+		},
+	}, {
+		name: "gpu_core",
+		enabledCollector: map[dcgm.Field_Entity_Group]struct{}{
+			dcgm.FE_CPU_CORE: struct{}{},
+		},
+	}, {
+		name: "gpu_switch_link",
+		enabledCollector: map[dcgm.Field_Entity_Group]struct{}{
+			dcgm.FE_SWITCH: struct{}{},
+			dcgm.FE_LINK:   struct{}{},
+		},
+	}, {
+		name: "gpu_cpu_core",
+		enabledCollector: map[dcgm.Field_Entity_Group]struct{}{
+			dcgm.FE_CPU:      struct{}{},
+			dcgm.FE_CPU_CORE: struct{}{},
+		},
+	}, {
+		name: "all",
+		enabledCollector: map[dcgm.Field_Entity_Group]struct{}{
+			dcgm.FE_SWITCH:   struct{}{},
+			dcgm.FE_LINK:     struct{}{},
+			dcgm.FE_CPU:      struct{}{},
+			dcgm.FE_CPU_CORE: struct{}{},
+		},
+	}} {
+		cleanupCounter := 0
+		_, cleanup, err := NewMetricsPipeline(&Config{
+			Kubernetes:     false,
+			ConfigMapData:  undefinedConfigMapData,
